refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
image = imresize(image, [64 96]);
gray = rgb2gray(image);
initialMask = imroi2mask([18 26 42 34], size(gray), "ellipse");
mask = imsegactivecontour(gray, initialMask, 3, 1);
subplot(1, 2, 1);
imshow(image);
subplot(1, 2, 2);
imshow(mask);
